import os

class IndexCache:
    def __init__(self):
        self.cache = {}

    def get_cache(self, index_file):
        if index_file not in self.cache:
            self.cache[index_file] = {}
        return self.cache[index_file]

    def remove_cache(self, index_file):
        if index_file in self.cache:
            del self.cache[index_file]

